#include <bits/stdc++.h>
using namespace std;
const int N=15;
long long dp[N][1<<9][105],cnt[1<<9];
int n,k;
int main()
{
	cin>>n>>k;
	for(int i=0;i<(1<<n);i++)
	{
		for(int j=0;j<n;j++)
		{
			if(i&(1<<j)) cnt[i]++;
		}
	}
	dp[0][0][0]=1;
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<(1<<n);j++)
		{
			if(j&(j>>1)) continue;
			for(int k1=0;k1<=k-cnt[j];k1++)
			{
				for(int j2=0;j2<(1<<n);j2++)
				{
					if((j2<<1)&j||(j2&j)||(j2>>1)&j) continue;
					dp[i][j][k1+cnt[j]]+=dp[i-1][j2][k1];
				}
			}
		}
	}
	long long ans=0;
	for(int i=0;i<(1<<n);i++) ans+=dp[n][i][k];
	cout<<ans;
	return 0;
}
